import React, { useEffect, useRef } from 'react';
import './Features.css';

const Features = () => {
  const features = [
    {
      icon: '🧠',
      title: '능동형 AI 상담',
      desc: '당신이 도움을 청하기 전에 먼저 다가가 감정을 이해하고 지원합니다',
      color: '#6c9eff',
      delay: '0s'
    },
    {
      icon: '📊',
      title: '감정 패턴 분석',
      desc: '대화 기록으로 감정 흐름을 분석하고 맞춤형 인사이트를 제공합니다',
      color: '#8b6fff',
      delay: '0.1s'
    },
    {
      icon: '🎨',
      title: '캐릭터 커스터마이징',
      desc: '하루와 루미 중 선택해 색상, 성격, 말투까지 나만의 AI를 만들어요',
      color: '#ff8fab',
      delay: '0.2s'
    },
    {
      icon: '🔒',
      title: '완벽한 프라이버시',
      desc: '모든 대화는 암호화되며 절대 공유되지 않습니다',
      color: '#14b8a6',
      delay: '0.3s'
    },
    {
      icon: '💬',
      title: '24/7 가용성',
      desc: '언제든지, 어디서든지 당신의 감정을 나눌 수 있습니다',
      color: '#0d9488',
      delay: '0.4s'
    },
    {
      icon: '⚡',
      title: '실시간 동기화',
      desc: '웹과 앱에서 완벽하게 동기화되어 이어서 대화를 나눕니다',
      color: '#0f766e',
      delay: '0.5s'
    }
  ];

  const containerRef = useRef(null);

  useEffect(() => {
    const observer = new IntersectionObserver(
      (entries) => {
        entries.forEach((entry) => {
          if (entry.isIntersecting) {
            entry.target.style.opacity = '1';
            entry.target.style.transform = 'translateY(0)';
          }
        });
      },
      { threshold: 0.1 }
    );

    document.querySelectorAll('.feature-card').forEach((card) => {
      card.style.opacity = '0';
      card.style.transform = 'translateY(30px)';
      card.style.transition = 'all 0.6s ease var(--delay)';
      observer.observe(card);
    });

    return () => observer.disconnect();
  }, []);

  return (
    <section className="features">
      <div className="container">
        <div className="section-header">
          <span className="section-badge">✨ 특징</span>
          <h2 className="section-title">메이티만의 특별함</h2>
          <p className="section-subtitle">
            최첨단 AI 기술과 인간적인 따뜻함을 결합한 감정 상담 서비스
          </p>
        </div>

        <div className="features-grid" ref={containerRef}>
          {features.map((feature, idx) => (
            <div
              key={idx}
              className="feature-card"
              style={{
                '--color': feature.color,
                '--delay': feature.delay
              }}
            >
              <div className="feature-icon">{feature.icon}</div>
              <h3>{feature.title}</h3>
              <p>{feature.desc}</p>
              <div className="feature-border" />
            </div>
          ))}
        </div>
      </div>
    </section>
  );
};

export default Features;
